command:
mkdir -p prompts && printf 'fine_tunes:
  - {artifact_id: dup, base_model: sonnet}
  - {artifact_id: dup, base_model: opus}
' > prompts/fine-tunes.yaml && bash "$CLAUDE_PLUGIN_ROOT/prompts/validate-fine-tunes.sh" --registry prompts/fine-tunes.yaml 2>err.txt; rc=$?; [ "$rc" -ne 0 ] && grep -q 'duplicate_artifact_id' err.txt && echo blocked 1>&2
